import{_ as r,o,c as a,a2 as l}from"./chunks/framework.gSjTt1Hm.js";const c=JSON.parse('{"title":"功能特性","description":"","frontmatter":{},"headers":[],"relativePath":"guide/features.md","filePath":"guide/features.md","lastUpdated":1783862549000}'),i={name:"guide/features.md"};function e(n,t,s,g,u,d){return o(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="功能特性" tabindex="-1">功能特性 <a class="header-anchor" href="#功能特性" aria-label="Permalink to &quot;功能特性&quot;">​</a></h1><h2 id="多平台统一接入" tabindex="-1">多平台统一接入 <a class="header-anchor" href="#多平台统一接入" aria-label="Permalink to &quot;多平台统一接入&quot;">​</a></h2><p>支持主流 AI 平台，统一为 OpenAI 兼容格式：</p><ul><li><strong>OpenAI</strong> — GPT-4o、GPT-4、GPT-3.5</li><li><strong>Anthropic</strong> — Claude 3.5、Claude 3</li><li><strong>Google</strong> — Gemini 1.5、Gemini Pro</li><li><strong>其他</strong> — 任何 OpenAI 兼容的 API</li></ul><h2 id="智能路由" tabindex="-1">智能路由 <a class="header-anchor" href="#智能路由" aria-label="Permalink to &quot;智能路由&quot;">​</a></h2><ul><li><strong>优先级路由</strong>：数值越小优先级越高</li><li><strong>权重路由</strong>：按权重比例分配请求</li><li><strong>故障转移</strong>：平台故障自动切换到其他平台</li><li><strong>熔断保护</strong>：连续失败后暂停请求，避免雪崩</li><li><strong>半开探测</strong>：冷却期后自动探测恢复</li></ul><h2 id="用量监控" tabindex="-1">用量监控 <a class="header-anchor" href="#用量监控" aria-label="Permalink to &quot;用量监控&quot;">​</a></h2><ul><li><strong>实时仪表盘</strong>：请求数、Token 用量、TTFT 延迟</li><li><strong>趋势图表</strong>：小时/天级别趋势，支持单日小时级展示</li><li><strong>平台对比</strong>：各平台的请求分布和性能对比</li><li><strong>模型统计</strong>：各模型的调用次数和 Token 消耗</li><li><strong>日志归档</strong>：30 天前的详细日志自动聚合为统计数据</li></ul><h2 id="api-key-管理" tabindex="-1">API Key 管理 <a class="header-anchor" href="#api-key-管理" aria-label="Permalink to &quot;API Key 管理&quot;">​</a></h2><ul><li><strong>多级配额</strong>：Token 额度、调用次数、RPM/TPM 限制</li><li><strong>套餐模板</strong>：预定义的配额模板，快速创建 Key</li><li><strong>自动重置</strong>：按月/按天/永不重置</li><li><strong>过期管理</strong>：设置过期时间，自动禁用</li></ul><h2 id="安全特性" tabindex="-1">安全特性 <a class="header-anchor" href="#安全特性" aria-label="Permalink to &quot;安全特性&quot;">​</a></h2><ul><li><strong>JWT 认证</strong>：管理员登录保护</li><li><strong>速率限制</strong>：平台级和 Key 级 RPM/TPM 限制</li><li><strong>安全头</strong>：CSP、HSTS、X-Frame-Options 等</li><li><strong>爬虫拦截</strong>：阻止搜索引擎和 AI 爬虫索引</li></ul><h2 id="数据管理" tabindex="-1">数据管理 <a class="header-anchor" href="#数据管理" aria-label="Permalink to &quot;数据管理&quot;">​</a></h2><ul><li><strong>数据导出</strong>：系统配置和业务数据完整导出</li><li><strong>数据导入</strong>：支持迁移和备份恢复</li><li><strong>审计日志</strong>：记录所有管理员操作</li></ul>',14)])])}const p=r(i,[["render",e]]);export{c as __pageData,p as default};
